#!/usr/bin/env python3
"""
Bug #0044: OnnxRuntime graph optimizer produces wrong output.

Patterns    : [['broadcast', 'broadcast_1d_scalar'], ['constant', 'add_self_sub_double'], ['constant', 'pad_slice_noop'], ['layout', 'resize_nearest_ceil'], ['layout', 'conv_transpose_channel_reorder'], ['branch', 'se_block']]
Dependencies: numpy onnx onnxruntime
Run         : python unique_0044.py  →  exit 0 = BUG REPRODUCED
"""
import os, sys
import numpy as np
import onnx, onnxruntime as ort

MODEL = os.path.join(os.path.dirname(os.path.abspath(__file__)), "unique_0044.onnx")
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])  # input "model_input"


def reference():
    """ORT with NO optimisation — ground truth."""
    opts = ort.SessionOptions()
    opts.graph_optimization_level = ort.GraphOptimizationLevel.ORT_DISABLE_ALL
    sess = ort.InferenceSession(MODEL, opts, providers=["CPUExecutionProvider"])
    return sess.run(None, {"model_input": INPUT})[0].ravel()


def target():
    """ORT with FULL graph optimisation — produces wrong output."""
    opts = ort.SessionOptions()
    opts.graph_optimization_level = ort.GraphOptimizationLevel.ORT_ENABLE_ALL
    sess = ort.InferenceSession(MODEL, opts, providers=["CPUExecutionProvider"])
    return sess.run(None, {"model_input": INPUT})[0].ravel()


if __name__ == "__main__":
    ref = reference()
    out = target()
    diff = float(np.linalg.norm(ref.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(ref.astype(np.float64)) + 1e-8))
    print(f"expected (ORT_DISABLE_ALL): {ref[:6]}")
    print(f"actual   (ORT_ENABLE_ALL) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
